<?php
if(session_status()===PHP_SESSION_NONE)session_start();if(empty($_SESSION['is_logged_in'])){header('Location: ../connexion.php');exit;}if(!in_array($_SESSION['user_type']??'', ['admin','gestionnaire'],true)){header('Location: dashboard.php');exit;}require_once __DIR__.'/../config/database.php';function th($v):string{return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
$tables=fetchAll('SELECT t.*,COUNT(o.id) order_count FROM tables t LEFT JOIN orders o ON o.table_id=t.id AND o.supprimer=0 WHERE t.supprimer=0 GROUP BY t.id ORDER BY t.number');$statusLabels=['available'=>'Disponible','occupied'=>'Occupée','reserved'=>'Réservée','cleaning'=>'Nettoyage'];$available=0;$seats=0;foreach($tables as $t){if($t->status==='available'&&$t->is_active)$available++;$seats+=(int)$t->capacity;}$name=trim(($_SESSION['user_nom']??'Utilisateur').' '.($_SESSION['user_prenom']??''));$initials=strtoupper(substr($_SESSION['user_nom']??'U',0,1).substr($_SESSION['user_prenom']??'',0,1));
?>
<!doctype html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Tables — ISSALE</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Outfit:wght@600;700&display=swap" rel="stylesheet"><link href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.1/font/bootstrap-icons.css" rel="stylesheet"><style>
:root{--p:#8B1A1A;--pd:#5C0E0E;--gold:#D4A373;--bg:#FDF8F3;--side:#1A120E;--text:#1A120E;--muted:#83766f;--border:#eadfd5;--green:#2d7d46;--red:#c0392b;--blue:#245c9e;--font:'Inter',sans-serif;--display:'Outfit',sans-serif}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font-family:var(--font)}.sidebar{position:fixed;inset:0 auto 0 0;width:256px;padding:24px;background:var(--side);display:flex;flex-direction:column;z-index:20}.brand{display:flex;gap:12px;align-items:center;margin-bottom:34px;color:#fff}.logo{width:42px;height:42px;border-radius:12px;background:linear-gradient(135deg,var(--p),var(--pd));display:grid;place-items:center}.brand h1{font:700 18px var(--display);margin:0}.brand small{color:var(--gold)}nav{display:grid;gap:5px}.label{color:#887d78;font-size:10px;font-weight:700;letter-spacing:.12em;margin:16px 12px 6px}.nav{display:flex;align-items:center;gap:12px;padding:11px 13px;color:#bdb5b1;text-decoration:none;border-radius:11px;font-size:14px}.nav:hover{color:#fff;background:#ffffff12}.nav.active{background:var(--gold);color:#1A120E;font-weight:700}.user{margin-top:auto;padding-top:18px;border-top:1px solid #ffffff14;display:flex;gap:10px;align-items:center;color:#fff}.avatar{width:38px;height:38px;border-radius:11px;background:#ffffff12;color:var(--gold);display:grid;place-items:center;font-weight:700}.user p{margin:0;font-size:13px;font-weight:600}.user span{font-size:11px;color:#918783}.logout{margin-left:auto;color:#aaa}.main{margin-left:256px}.top{position:sticky;top:0;z-index:10;padding:17px 30px;background:#fdf8f3e8;backdrop-filter:blur(12px);border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center}.top h2{font:700 23px var(--display);margin:0}.top small{color:var(--muted)}.menu-btn{display:none;border:0;background:none;font-size:24px}.content{padding:30px}.crumb{font-size:13px;color:var(--muted);margin-bottom:20px}.crumb a{color:var(--p);text-decoration:none}.stats{display:grid;grid-template-columns:repeat(3,1fr);gap:15px;margin-bottom:22px}.stat{background:#fff;border:1px solid var(--border);border-radius:15px;padding:19px}.stat span{font-size:11px;text-transform:uppercase;color:var(--muted);font-weight:700}.stat strong{display:block;font:700 27px var(--display);margin-top:7px}.toolbar{display:flex;justify-content:space-between;gap:15px;margin-bottom:18px}.search{position:relative;max-width:380px;flex:1}.search i{position:absolute;left:14px;top:13px;color:#a39790}.search input,.filter{width:100%;padding:12px 14px 12px 40px;border:1px solid var(--border);border-radius:11px;background:#fff;font:14px var(--font)}.filter{padding-left:14px;width:auto}.tools{display:flex;gap:10px}.btn{border:0;border-radius:11px;padding:11px 17px;font:600 13px var(--font);cursor:pointer;display:inline-flex;align-items:center;gap:8px}.primary{background:var(--p);color:#fff}.light{background:#f4ede7}.card{background:#fff;border:1px solid var(--border);border-radius:18px;overflow:hidden}.wrap{overflow:auto}table{width:100%;border-collapse:collapse}th{background:#fbf6f1;padding:13px 18px;text-align:left;text-transform:uppercase;letter-spacing:.06em;font-size:10px;color:#94867e}td{padding:15px 18px;border-top:1px solid var(--border);font-size:13px;color:var(--muted)}tr:hover td{background:#fdf9f5}.table-name{display:flex;align-items:center;gap:11px;color:var(--text);font-weight:700}.table-icon{width:39px;height:39px;border-radius:11px;background:#f7e8e8;color:var(--p);display:grid;place-items:center}.badge{display:inline-block;padding:5px 9px;border-radius:99px;font-size:10px;font-weight:700}.available{background:#e8f5ec;color:var(--green)}.occupied{background:#fce8e8;color:var(--p)}.reserved{background:#e8f1ff;color:var(--blue)}.cleaning{background:#fff0df;color:#8a580d}.inactive{background:#eee;color:#666}.actions{display:flex;gap:6px}.icon{width:32px;height:32px;border:1px solid var(--border);border-radius:8px;background:#fff;cursor:pointer;color:#75675f}.icon:hover{color:var(--p);border-color:var(--p)}.empty{text-align:center;padding:55px}.overlay{position:fixed;inset:0;background:#1a120e88;display:none;align-items:center;justify-content:center;padding:20px;z-index:100}.overlay.open{display:flex}.modal{width:min(540px,100%);background:#fff;border-radius:20px;box-shadow:0 24px 70px #0004}.head{display:flex;justify-content:space-between;padding:22px 24px;border-bottom:1px solid var(--border)}.head h3{font:700 19px var(--display);margin:0}.close{border:0;background:none;font-size:23px}.body{padding:24px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:16px}.field label{display:block;font-size:12px;font-weight:700;margin-bottom:7px}.field input,.field select{width:100%;padding:11px;border:1px solid var(--border);border-radius:10px;font:14px var(--font)}.full{grid-column:1/-1}.check{display:flex;gap:9px;align-items:center}.foot{display:flex;justify-content:flex-end;gap:9px;padding:18px 24px;border-top:1px solid var(--border)}.toast{position:fixed;right:22px;bottom:22px;background:#1A120E;color:#fff;padding:14px 18px;border-radius:11px;z-index:200}.mobile-overlay{display:none}@media(max-width:768px){.sidebar{transform:translateX(-100%);transition:.2s}.sidebar.open{transform:none}.mobile-overlay.open{display:block;position:fixed;inset:0;background:#0006;z-index:15}.main{margin-left:0}.menu-btn{display:block}.content{padding:20px 16px}.stats{grid-template-columns:1fr}.toolbar{flex-direction:column}.tools{flex-wrap:wrap}.grid{grid-template-columns:1fr}.full{grid-column:auto}}
</style></head><body><aside class="sidebar" id="sidebar"><div class="brand"><div class="logo"><i class="bi bi-cup-hot-fill"></i></div><div><h1>ISSALE</h1><small>Administration</small></div></div><nav><div class="label">Menu</div><a class="nav" href="dashboard.php"><i class="bi bi-grid-1x2"></i>Tableau de bord</a><a class="nav" href="menus.php"><i class="bi bi-journal-richtext"></i>Menus</a><a class="nav" href="categories.php"><i class="bi bi-tags"></i>Catégories</a><a class="nav active" href="tables.php"><i class="bi bi-grid-3x3-gap"></i>Tables</a><?php if(($_SESSION['user_type']??'')==='admin'):?><a class="nav" href="utilisateurs.php"><i class="bi bi-people"></i>Utilisateurs</a><?php endif;?><a class="nav" href="settings.php"><i class="bi bi-gear"></i>Paramètres</a></nav><div class="user"><div class="avatar"><?=th($initials)?></div><div><p><?=th($name)?></p><span><?=th(ucfirst($_SESSION['user_type']??''))?></span></div><a class="logout" href="../models/logout.php"><i class="bi bi-box-arrow-right"></i></a></div></aside><div class="mobile-overlay" id="mobileOverlay" onclick="toggleSidebar()"></div>
<main class="main"><header class="top"><div style="display:flex;align-items:center;gap:12px"><button class="menu-btn" onclick="toggleSidebar()"><i class="bi bi-list"></i></button><div><h2>Gestion des tables</h2><small>Capacités, disponibilités et QR codes</small></div></div><span class="badge reserved">Salle ISSALE</span></header><section class="content"><div class="crumb"><a href="dashboard.php">Tableau de bord</a> &nbsp;/&nbsp; Tables</div><div class="stats"><div class="stat"><span>Total tables</span><strong><?=count($tables)?></strong></div><div class="stat"><span>Tables disponibles</span><strong><?=$available?></strong></div><div class="stat"><span>Capacité totale</span><strong><?=$seats?> places</strong></div></div><div class="toolbar"><div class="search"><i class="bi bi-search"></i><input id="search" oninput="filterTables()" placeholder="Rechercher une table…"></div><div class="tools"><select class="filter" id="statusFilter" onchange="filterTables()"><option value="">Tous les statuts</option><?php foreach($statusLabels as $key=>$label):?><option value="<?=th($key)?>"><?=th($label)?></option><?php endforeach;?></select><button class="btn primary" onclick="openTable()"><i class="bi bi-plus-lg"></i>Ajouter une table</button></div></div><div class="card"><div class="wrap"><table><thead><tr><th>Table</th><th>Capacité</th><th>Statut</th><th>QR Token</th><th>Commandes</th><th>Actions</th></tr></thead><tbody id="rows"><?php if(!$tables):?><tr><td colspan="6" class="empty">Aucune table enregistrée.</td></tr><?php endif;?><?php foreach($tables as $t):?><tr id="table-<?=$t->id?>" data-status="<?=th($t->status)?>" data-search="<?=th(strtolower($t->number.' '.$statusLabels[$t->status]))?>"><td><div class="table-name"><span class="table-icon"><i class="bi bi-grid-3x3-gap"></i></span><?=th($t->number)?><?php if(!$t->is_active):?><span class="badge inactive">Inactive</span><?php endif;?></div></td><td><?=$t->capacity?> place<?=$t->capacity>1?'s':''?></td><td><span class="badge <?=th($t->status)?>"><?=th($statusLabels[$t->status]??$t->status)?></span></td><td><code><?=th($t->qr_code_token?substr($t->qr_code_token,0,10).'…':'—')?></code></td><td><?=$t->order_count?></td><td><div class="actions"><button class="icon" onclick='editTable(<?=json_encode($t,JSON_HEX_APOS|JSON_HEX_QUOT)?>)'><i class="bi bi-pencil"></i></button><button class="icon" onclick="askDelete(<?=$t->id?>,<?=th(json_encode($t->number))?>,<?=$t->order_count?>)"><i class="bi bi-trash"></i></button></div></td></tr><?php endforeach;?></tbody></table></div></div></section></main>
<div class="overlay" id="tableModal"><form class="modal" id="tableForm" onsubmit="saveTable(event)"><div class="head"><h3 id="modalTitle">Ajouter une table</h3><button type="button" class="close" onclick="closeTable()">×</button></div><div class="body"><input type="hidden" name="action" id="action" value="create"><input type="hidden" name="id" id="tableId"><div class="grid"><div class="field"><label>Numéro *</label><input name="number" id="number" required placeholder="Ex. T-06"></div><div class="field"><label>Capacité *</label><input type="number" min="1" name="capacity" id="capacity" value="4" required></div><div class="field full"><label>Statut *</label><select name="status" id="status"><?php foreach($statusLabels as $key=>$label):?><option value="<?=th($key)?>"><?=th($label)?></option><?php endforeach;?></select></div><div class="field full check"><input style="width:auto" type="checkbox" name="is_active" id="active" value="1" checked><label style="margin:0">Table active</label></div></div></div><div class="foot"><button type="button" class="btn light" onclick="closeTable()">Annuler</button><button class="btn primary" id="saveBtn">Enregistrer</button></div></form></div>
<div class="overlay" id="deleteModal"><div class="modal" style="max-width:430px"><div class="head"><h3>Confirmer la suppression</h3><button class="close" onclick="closeDelete()">×</button></div><div class="body" style="text-align:center"><div style="width:58px;height:58px;border-radius:50%;display:grid;place-items:center;margin:0 auto 16px;background:#fce8e8;color:var(--red);font-size:25px"><i class="bi bi-exclamation-triangle"></i></div><p>Voulez-vous supprimer la table</p><strong id="deleteName" style="color:var(--p)"></strong><p id="deleteWarning" style="font-size:12px;color:var(--red)"></p></div><div class="foot"><button class="btn light" onclick="closeDelete()">Annuler</button><button class="btn" id="deleteBtn" style="background:var(--red);color:#fff" onclick="executeDelete()"><i class="bi bi-trash"></i>Supprimer</button></div></div></div>
<script>
let tableToDelete=null;function toggleSidebar(){sidebar.classList.toggle('open');mobileOverlay.classList.toggle('open')}function openTable(){tableForm.reset();action.value='create';tableId.value='';capacity.value=4;active.checked=true;modalTitle.textContent='Ajouter une table';tableModal.classList.add('open')}function editTable(t){tableForm.reset();action.value='update';tableId.value=t.id;number.value=t.number;capacity.value=t.capacity;status.value=t.status;active.checked=Number(t.is_active)===1;modalTitle.textContent='Modifier la table';tableModal.classList.add('open')}function closeTable(){tableModal.classList.remove('open')}async function saveTable(e){e.preventDefault();saveBtn.disabled=true;const data=Object.fromEntries(new FormData(tableForm));try{const r=await fetch('../models/traitement/tables-post.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)}),o=await r.json();toast(o.message);if(o.success)setTimeout(()=>location.reload(),600)}catch(e){toast('Une erreur est survenue.')}finally{saveBtn.disabled=false}}
function askDelete(id,name,count){tableToDelete=id;deleteName.textContent=name;deleteWarning.textContent=count>0?'Cette table est liée à '+count+' commande(s) et ne peut pas être supprimée.':'';deleteBtn.disabled=count>0;deleteModal.classList.add('open')}function closeDelete(){deleteModal.classList.remove('open');tableToDelete=null}async function executeDelete(){if(!tableToDelete)return;deleteBtn.disabled=true;const id=tableToDelete;try{const r=await fetch('../models/traitement/tables-post.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'delete',id})}),o=await r.json();toast(o.message);if(o.success){document.getElementById('table-'+id)?.remove();closeDelete()}}catch(e){toast('Une erreur est survenue.')}finally{deleteBtn.disabled=false}}function filterTables(){const q=search.value.toLowerCase(),s=statusFilter.value;document.querySelectorAll('#rows tr[data-search]').forEach(r=>r.style.display=(!q||r.dataset.search.includes(q))&&(!s||r.dataset.status===s)?'':'none')}function toast(msg){document.querySelector('.toast')?.remove();const t=document.createElement('div');t.className='toast';t.textContent=msg;document.body.append(t);setTimeout(()=>t.remove(),3500)}tableModal.onclick=e=>{if(e.target===tableModal)closeTable()};deleteModal.onclick=e=>{if(e.target===deleteModal)closeDelete()};document.addEventListener('keydown',e=>{if(e.key==='Escape'){closeTable();closeDelete()}});
</script><script src="../assets/js/sidebar-sync.js"></script></body></html>
